import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size
        int maxBufferSize = 10;

        // Ensure userInput does not exceed maxBufferSize
        if (userInput.length() > maxBufferSize) {
            System.out.println("Input exceeds maximum buffer size.");
            return;
        }

        // No need to manually copy user input into a fixed-size buffer
        System.out.println("User input: " + userInput);
    }
}

